/**
 * Unit Tests: Logger Service
 * Testa o módulo centralizado de logging (src/lib/logger.ts)
 */

import { Logger, logger } from '@/lib/logger';

describe('Logger', () => {
  let consoleSpy: {
    debug: jest.SpyInstance;
    info: jest.SpyInstance;
    warn: jest.SpyInstance;
    error: jest.SpyInstance;
  };

  beforeEach(() => {
    consoleSpy = {
      debug: jest.spyOn(console, 'debug').mockImplementation(),
      info: jest.spyOn(console, 'info').mockImplementation(),
      warn: jest.spyOn(console, 'warn').mockImplementation(),
      error: jest.spyOn(console, 'error').mockImplementation(),
    };
  });

  afterEach(() => {
    jest.restoreAllMocks();
  });

  describe('singleton export', () => {
    it('should export a default logger instance', () => {
      expect(logger).toBeInstanceOf(Logger);
    });

    it('should expose debug/info/warn/error methods', () => {
      expect(typeof logger.debug).toBe('function');
      expect(typeof logger.info).toBe('function');
      expect(typeof logger.warn).toBe('function');
      expect(typeof logger.error).toBe('function');
    });
  });

  describe('log levels', () => {
    it('should log info messages', () => {
      logger.info('Test info message');
      expect(consoleSpy.info).toHaveBeenCalled();
    });

    it('should log warn messages', () => {
      logger.warn('Test warning');
      expect(consoleSpy.warn).toHaveBeenCalled();
    });

    it('should log error messages', () => {
      logger.error('Test error');
      expect(consoleSpy.error).toHaveBeenCalled();
    });
  });

  describe('error handling', () => {
    it('should accept Error objects', () => {
      const error = new Error('Something broke');
      logger.error('Failed operation', error);
      expect(consoleSpy.error).toHaveBeenCalled();
    });

    it('should accept context with error', () => {
      const error = new Error('Render failed');
      logger.error('Failed operation', error, { jobId: 'job-123' });
      expect(consoleSpy.error).toHaveBeenCalled();
    });
  });

  describe('context', () => {
    it('should accept context objects', () => {
      logger.info('Operation complete', { duration: 150, status: 'ok' });
      expect(consoleSpy.info).toHaveBeenCalled();
    });
  });

  describe('custom namespace', () => {
    it('should create logger with namespace', () => {
      const nsLogger = new Logger('render-worker');
      expect(nsLogger).toBeInstanceOf(Logger);
      nsLogger.info('Worker started');
      expect(consoleSpy.info).toHaveBeenCalled();
    });
  });

  describe('withContext', () => {
    it('should return a new Logger instance with merged context', () => {
      const contextLogger = logger.withContext({ requestId: 'req-abc' });
      expect(contextLogger).toBeInstanceOf(Logger);
      contextLogger.info('Request processed');
      expect(consoleSpy.info).toHaveBeenCalled();
    });
  });
});
